// 极简BA动画JS，控制台打印滚动值/位移值/触发状态，无冗余
console.clear(); // 清空之前的日志
console.log('=== 用类名控制BA动画 ===');

document.addEventListener('DOMContentLoaded', function() {
    const config = {
        trigger: 900,
        reset: 500
    };

    const baImg = document.querySelector('img[src*="bile-acid.webp"]');
    console.log('是否找到BA图片：', baImg ? '✅ 找到' : '❌ 没找到');

    function baAnimation() {
        const scrollY = window.scrollY;
        console.log('当前滚动值：', scrollY);

        if (baImg) {
            if (scrollY >= config.trigger) {
                baImg.classList.add('ba-animate');
                baImg.classList.remove('ba-reset');
                console.log('✅ 触发BA动画（类名控制）');
            } else if (scrollY < config.reset) {
                baImg.classList.add('ba-reset');
                baImg.classList.remove('ba-animate');
                console.log('🔙 重置BA位置（类名控制）');
            }
        }
    }

    window.addEventListener('scroll', baAnimation, { passive: true });
    baAnimation();
});